class Solution {
    public int numWays(int steps, int arrLen) {
        final int MOD = (int)1e9 + 7;
        int[] dp = new int[steps + 1];
        dp[0] = 1;
        for (int i = 1; i <= steps; i++) {
            dp[i] = dp[i - 1];
            if (i - 1 >= 0) dp[i] = (dp[i] + dp[i - 1]) % MOD;
            if (i - 2 >= 0) dp[i] = (dp[i] + dp[i - 2]) % MOD;
        }
        return dp[steps];
    }
}
